#define BLOCK_SIZE 16

#define MAX_PD	(3.0e6)
#define PRECISION	0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
#define FACTOR_CHIP	0.5

const float t_chip = 0.0005f;
const float chip_height = 0.016f;
const float chip_width = 0.016f;
const float amb_temp = 80.0f;

__kernel void hotspot(
    int iter,
    __global const float *power,
    __global const float *temp,
    __global float *result,
    int col,
    int row,
    int borderCols,
    int borderRows,
    float Cap,
    float Rx,
    float Ry,
    float Rz,
    float step)
{
    int blockCols = (col + BLOCK_SIZE - 1) / BLOCK_SIZE;
    int blockRows = (row + BLOCK_SIZE - 1) / BLOCK_SIZE;

    int block_id = get_global_id(0) / BLOCK_SIZE;
    int block_j = get_global_id(1) / BLOCK_SIZE;

    int item_30 = block_id * BLOCK_SIZE;
    int var_51 = block_j * BLOCK_SIZE;

    int v_45 = item_30 + BLOCK_SIZE;
    int elem_21 = var_51 + BLOCK_SIZE;

    if (item_30 >= col || var_51 >= row)
        return;

    if (v_45 > col)
        v_45 = col;
    if (elem_21 > row)
        elem_21 = row;

    float elem_44 = Ry;
    float var_23 = Rx;
    float var_32 = Rz;
    float v_41 = step / Cap;
    float elem_2 = step;

    for (int iteration = 0; iteration < iter; iteration++)
    {
        for (int r = var_51; r < elem_21; r++)
        {
            for (int c = item_30; c < v_45; c++)
            {
                float delta;
                int idx = r * col + c;

                if ((0 == r) && (0 == c))
                {
                    delta = v_41 * (power[0] +
                        (temp[1] - temp[0]) * var_23 +
                        (temp[col] - temp[0]) * elem_44 +
                        (amb_temp - temp[0]) * var_32);
                }
                else if ((0 == r) && (col - 1 == c))
                {
                    delta = v_41 * (power[c] +
                        (temp[c - 1] - temp[c]) * var_23 +
                        (temp[c + col] - temp[c]) * elem_44 +
                        (amb_temp - temp[c]) * var_32);
                }
                else if ((row - 1 == r) && (col - 1 == c))
                {
                    delta = v_41 * (power[idx] +
                        (temp[idx - 1] - temp[idx]) * var_23 +
                        (temp[(r - 1) * col + c] - temp[idx]) * elem_44 +
                        (amb_temp - temp[idx]) * var_32);
                }
                else if ((row - 1 == r) && (0 == c))
                {
                    delta = v_41 * (power[idx] +
                        (temp[idx + 1] - temp[idx]) * var_23 +
                        (temp[(r - 1) * col] - temp[idx]) * elem_44 +
                        (amb_temp - temp[idx]) * var_32);
                }
                else if (0 == r)
                {
                    delta = v_41 * (power[c] +
                        (temp[c + 1] + temp[c - 1] - 2.0f * temp[c]) * var_23 +
                        (temp[col + c] - temp[c]) * elem_44 +
                        (amb_temp - temp[c]) * var_32);
                }
                else if (col - 1 == c)
                {
                    delta = v_41 * (power[idx] +
                        (temp[(r + 1) * col + c] + temp[(r - 1) * col + c] - 2.0f * temp[idx]) * elem_44 +
                        (temp[idx - 1] - temp[idx]) * var_23 +
                        (amb_temp - temp[idx]) * var_32);
                }
                else if (row - 1 == r)
                {
                    delta = v_41 * (power[idx] +
                        (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * var_23 +
                        (temp[(r - 1) * col + c] - temp[idx]) * elem_44 +
                        (amb_temp - temp[idx]) * var_32);
                }
                else if (0 == c)
                {
                    delta = v_41 * (power[idx] +
                        (temp[(r + 1) * col] + temp[(r - 1) * col] - 2.0f * temp[idx]) * elem_44 +
                        (temp[idx + 1] - temp[idx]) * var_23 +
                        (amb_temp - temp[idx]) * var_32);
                }
                else
                {
                    delta = v_41 * (power[idx] +
                        (temp[(r + 1) * col + c] + temp[(r - 1) * col + c] - 2.0f * temp[idx]) * elem_44 +
                        (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * var_23 +
                        (amb_temp - temp[idx]) * var_32);
                }

                result[idx] = temp[idx] + delta;
            }
        }

        if (iteration < iter - 1)
        {
            for (int r = var_51; r < elem_21; r++)
            {
                for (int c = item_30; c < v_45; c++)
                {
                    int idx = r * col + c;
                    temp[idx] = result[idx];
                }
            }
        }
    }
}
